// INCORRECT: Untyped payloads produce weak validation and vague OpenAPI schemas.
@Post()
create(@Body() body: any) {
  return this.usersService.create(body);
}

correct:
// CORRECT: DTOs and response types keep runtime validation and OpenAPI aligned.
@Post()
@ApiCreatedResponse({ type: UserResponseDto })
create(@Body() dto: CreateUserDto): Promise<UserResponseDto> {
  return this.usersService.create(dto);
}

// CORRECT: Public errors use a stable, documented envelope.
throw new BadRequestException({
  code: "INVALID_REQUEST",
  message: "Invalid request",
});

incorrect:
// INCORRECT: Credentialed wildcard CORS is too broad.
app.enableCors({
  origin: true,
  credentials: true,
});

correct:
// CORRECT: Centralized, explicit HTTP policy in bootstrap.
app.enableCors({
  origin: config.allowedOrigins,
  credentials: true,
});
app.use(helmet());

incorrect:
// INCORRECT: The user is authenticated, but ownership is never checked.
@UseGuards(JwtAuthGuard)
@Delete(":id")
remove(@Param("id") id: string) {
  return this.postsService.remove(id);
}

correct:
// CORRECT: The service receives the actor and enforces resource policy.
@UseGuards(JwtAuthGuard)
@Delete(":id")
remove(@CurrentUser() user: User, @Param("id") id: string) {
  return this.postsService.removeForActor(user.id, id);
}

